insert into public.exercises (id, name, muscle_group, equipment, target, secondary_muscles, instructions, gif_path) values
  ('db-2800', 'barbell sitted alternate leg raise (female)', 'Core', 'Barbell', 'abs', ARRAY['hip flexors','quadriceps']::text[], ARRAY['Sit on a bench with your back straight and hold a barbell across your thighs.','Place your hands on the sides of the bench for support.','Keeping your legs straight, lift one leg up as high as possible while keeping it parallel to the ground.','Lower the leg back down and repeat with the other leg.','Continue alternating legs for the desired number of repetitions.']::text[], 'BCs0G2F'),
  ('db-0100', 'barbell skier', 'Shoulders', 'Barbell', 'delts', ARRAY['triceps','core']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip.','Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.','Simultaneously lift the barbell up towards your shoulders while jumping slightly off the ground.','As you reach the top of the movement, quickly reverse the motion and lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '4Leypho'),
  ('db-0101', 'barbell speed squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, toes slightly turned out.','Hold the barbell across your upper back, resting it on your traps or rear delts.','Engage your core and keep your chest up as you lower your hips back and down, as if sitting into a chair.','Lower until your thighs are parallel to the ground, or as low as you can comfortably go.','Drive through your heels to stand back up, squeezing your glutes at the top.','Repeat for the desired number of repetitions.']::text[], 'euI1BwR'),
  ('db-2810', 'barbell split squat v. 2', 'Legs', 'Barbell', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.','Take a large step forward with your right foot, keeping your torso upright.','Lower your body by bending your knees and hips until your right thigh is parallel to the ground.','Pause for a moment, then push through your right heel to return to the starting position.','Repeat with your left leg forward for the desired number of repetitions.']::text[], 'HBYyX94'),
  ('db-0102', 'barbell squat (on knees)', 'Legs', 'Barbell', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Start by kneeling on the ground with your knees hip-width apart and your toes pointing forward.','Place a barbell across your shoulders, gripping it with an overhand grip and your hands slightly wider than shoulder-width apart.','Engage your core and keep your chest lifted as you slowly lower your body down by bending your knees, keeping your back straight.','Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'oR7O9LW'),
  ('db-2798', 'barbell squat jump step rear lunge', 'Legs', 'Barbell', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.','Lower your body into a squat position by bending your knees and pushing your hips back.','Explode upwards, jumping off the ground as high as you can.','Land softly on your feet and immediately step back with one leg into a reverse lunge.','Lower your body down until your front thigh is parallel to the ground, keeping your back straight.','Push through your front heel to return to the starting position.','Repeat the jump and lunge sequence on the other leg.','Continue alternating legs for the desired number of repetitions.']::text[], 'RYcV1kH'),
  ('db-0103', 'barbell standing ab rollerout', 'Core', 'Barbell', 'abs', ARRAY['shoulders','lower back']::text[], ARRAY['Stand upright with your feet shoulder-width apart and hold the barbell with both hands in front of your thighs.','Engage your core and slowly roll the barbell down towards the ground, keeping your back straight and your arms extended.','Continue rolling the barbell forward until your body is fully extended and your hands are directly above your head.','Pause for a moment, then slowly roll the barbell back towards your thighs, maintaining control and keeping your core engaged.','Repeat for the desired number of repetitions.']::text[], 'xnInPfE'),
  ('db-0104', 'barbell standing back wrist curl', 'Arms', 'Barbell', 'forearms', ARRAY['biceps','shoulders']::text[], ARRAY['Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip.','Rest the barbell on the back of your hands with your palms facing down and your fingers pointing towards your body.','Keeping your upper arms stationary, exhale and curl your wrists upwards as far as possible.','Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], '2qTvJAZ'),
  ('db-0105', 'barbell standing bradford press', 'Shoulders', 'Barbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the barbell in front of your shoulders with an overhand grip.','Press the barbell overhead, fully extending your arms.','Lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'dCPESfR'),
  ('db-1372', 'barbell standing calf raise', 'Legs', 'Barbell', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart and place a barbell across your upper back.','Raise your heels off the ground as high as possible, using only your toes.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '8ozhUIZ'),
  ('db-0106', 'barbell standing close grip curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, hands close together.','Keep your elbows close to your torso and your upper arms stationary throughout the movement.','Exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale as you slowly begin to bring the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], '4dUn2iv'),
  ('db-1456', 'barbell standing close grip military press', 'Shoulders', 'Barbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, hands slightly closer than shoulder-width apart.','Lift the barbell to shoulder height, keeping your elbows close to your body.','Press the barbell overhead, extending your arms fully.','Lower the barbell back to shoulder height.','Repeat for the desired number of repetitions.']::text[], 'wdRZISl'),
  ('db-2414', 'barbell standing concentration curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell in one hand, palm facing up.','Rest your opposite hand on your thigh for support.','Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder.','Pause for a moment at the top, squeezing your biceps.','Inhale and slowly lower the weight back down to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'vsMcDi9'),
  ('db-0107', 'barbell standing front raise over head', 'Shoulders', 'Barbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a barbell in front of your thighs with an overhand grip.','Keep your back straight and engage your core.','Slowly raise the barbell in front of you, keeping your arms straight and your palms facing down.','Continue lifting until the barbell is slightly above shoulder level.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'S8mo30S'),
  ('db-0108', 'barbell standing leg calf raise', 'Legs', 'Barbell', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart and place a barbell across your upper back.','Raise your heels off the ground as high as possible, using your calves.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'rGwhJ5o'),
  ('db-0109', 'barbell standing overhead triceps extension', 'Arms', 'Barbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with an overhand grip.','Raise the barbell overhead, fully extending your arms.','Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows.','Pause for a moment, then raise the barbell back to the starting position by extending your arms.','Repeat for the desired number of repetitions.']::text[], 'dZl9Q27'),
  ('db-0110', 'barbell standing reverse grip curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.','Keep your elbows close to your torso and your upper arms stationary.','Exhale and curl the weights while contracting your biceps, bringing the barbell as close to your shoulders as possible.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'LWuA3aZ'),
  ('db-0111', 'barbell standing rocking leg calf raise', 'Legs', 'Barbell', 'calves', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell across your upper back.','Raise your heels off the ground as high as possible, balancing on the balls of your feet.','Slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '6HiHHe0'),
  ('db-0112', 'barbell standing twist', 'Core', 'Barbell', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell in front of your chest with both hands, palms facing down.','Engage your core and keep your back straight throughout the exercise.','Slowly twist your torso to the right, pivoting on your feet and hips, while keeping your lower body stable.','Pause for a moment at the end of the twist, then slowly return to the starting position.','Repeat the twist to the left side.','Continue alternating twists for the desired number of repetitions.']::text[], 'yQe5HpE'),
  ('db-1629', 'barbell standing wide grip biceps curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, hands wider than shoulder-width apart.','Keep your back straight and your elbows close to your torso.','Exhale and curl the barbell up towards your shoulders, keeping your upper arms stationary.','Pause for a moment at the top, squeezing your biceps.','Inhale and slowly lower the barbell back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'faHKVkK'),
  ('db-1457', 'barbell standing wide military press', 'Shoulders', 'Barbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, slightly wider than shoulder-width.','Lift the barbell to shoulder height, keeping your elbows slightly in front of the bar.','Press the barbell overhead, extending your arms fully.','Lower the barbell back to shoulder height and repeat for the desired number of repetitions.']::text[], 'Kyd9Rz5'),
  ('db-0113', 'barbell standing wide-grip curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms','shoulders']::text[], ARRAY['Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart.','Let the barbell hang at arm''s length in front of your thighs, with your palms facing away from your body.','Keeping your upper arms stationary, exhale and curl the barbell upward by contracting your biceps.','Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'NdIb5Z1'),
  ('db-0114', 'barbell step-up', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand in front of a bench or step with a barbell resting on your upper back.','Place one foot on the bench or step, ensuring your entire foot is in contact with the surface.','Push through your heel and step up onto the bench or step, fully extending your hip and knee.','Pause briefly at the top, then lower yourself back down to the starting position.','Repeat with the opposite leg.','Continue alternating legs for the desired number of repetitions.']::text[], 'Kxquu2E'),
  ('db-0115', 'barbell stiff leg good morning', 'Legs', 'Barbell', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Hold the barbell across your upper back, resting it on your traps.','Keeping your back straight, hinge forward at the hips, pushing your glutes back.','Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.','Engage your glutes and hamstrings to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'JrOHAZc'),
  ('db-0116', 'barbell straight leg deadlift', 'Legs', 'Barbell', 'hamstrings', ARRAY['glutes','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart and your toes pointing forward.','Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Bend at your hips and lower the barbell towards the ground, keeping your back straight and your knees slightly bent.','Lower the barbell until you feel a stretch in your hamstrings.','Engage your hamstrings and glutes to lift the barbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'hrVQWvE'),
  ('db-0117', 'barbell sumo deadlift', 'Legs', 'Barbell', 'glutes', ARRAY['hamstrings','quadriceps','lower back']::text[], ARRAY['Stand with your feet wider than shoulder-width apart, toes pointing outwards.','Place a barbell on the ground in front of you, centered between your feet.','Bend your knees and lower your hips, keeping your back straight and chest up, to grip the barbell with an overhand grip.','Engage your core and drive through your heels to lift the barbell off the ground, extending your hips and knees simultaneously.','As you lift, keep your chest up and back straight, and push your hips forward to fully engage your glutes.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position, maintaining control throughout the movement.','Repeat for the desired number of repetitions.']::text[], 'KgI0tqW'),
  ('db-3305', 'barbell thruster', 'Shoulders', 'Barbell', 'delts', ARRAY['quadriceps','glutes','hamstrings','core']::text[], ARRAY['Start by standing with your feet shoulder-width apart, holding a barbell at shoulder height with an overhand grip.','Lower into a squat position by bending your knees and pushing your hips back.','As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the barbell overhead.','Lower the barbell back to shoulder height as you lower back into the squat position.','Repeat for the desired number of repetitions.']::text[], 'f7Y9eDZ'),
  ('db-0120', 'barbell upright row', 'Shoulders', 'Barbell', 'delts', ARRAY['traps','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Let the barbell hang in front of your thighs, arms fully extended.','Keeping your back straight and core engaged, exhale and lift the barbell straight up towards your chin, leading with your elbows.','Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'UDlhcO8'),
  ('db-0119', 'barbell upright row v. 2', 'Shoulders', 'Barbell', 'delts', ARRAY['traps','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Let the barbell hang in front of your thighs, arms fully extended.','Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows.','Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '83HoW9X'),
  ('db-0121', 'barbell upright row v. 3', 'Shoulders', 'Barbell', 'delts', ARRAY['traps','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Let the barbell hang in front of your thighs, arms fully extended.','Keeping your core engaged and back straight, exhale as you lift the barbell straight up towards your chin, leading with your elbows.','Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'fI18Rbc'),
  ('db-0122', 'barbell wide bench press', 'Chest', 'Barbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.','Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.','Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.','Lower the barbell slowly towards your chest, keeping your elbows slightly flared out.','Pause for a moment when the barbell touches your chest, then push it back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'JsKq9so'),
  ('db-1258', 'barbell wide reverse grip bench press', 'Chest', 'Barbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.','Grasp the barbell with a wide reverse grip, slightly wider than shoulder-width apart.','Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.','Lower the barbell slowly towards your chest, keeping your elbows tucked in and your wrists straight.','Pause for a moment when the barbell touches your chest, then push it back up to the starting position.','Repeat for the desired number of repetitions.']::text[], '945zpRg'),
  ('db-0124', 'barbell wide squat', 'Legs', 'Barbell', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.','Hold the barbell across your upper back, resting it on your traps or rear delts.','Engage your core and keep your chest up as you lower your body down into a squat, pushing your hips back and bending your knees.','Lower until your thighs are parallel to the ground, or as low as you can comfortably go.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 's7HX1BY'),
  ('db-0123', 'barbell wide-grip upright row', 'Shoulders', 'Barbell', 'delts', ARRAY['traps','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart.','Let the barbell hang in front of your thighs, arms fully extended.','Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows.','Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'RgJDRR1'),
  ('db-0126', 'barbell wrist curl', 'Arms', 'Barbell', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, holding a barbell with an underhand grip.','Allow the barbell to roll down to your fingertips, keeping your wrists straight.','Slowly curl the barbell up towards your forearms by flexing your wrists.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '82LxxkW'),
  ('db-0125', 'barbell wrist curl v. 2', 'Arms', 'Barbell', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench with your feet flat on the ground and your knees bent.','Hold a barbell with an underhand grip, palms facing up, and your hands shoulder-width apart.','Rest your forearms on your thighs, allowing your wrists to hang off the edge.','Slowly curl your wrists upward, bringing the barbell towards your forearms.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '6kSxYnw'),
  ('db-0127', 'barbell zercher squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves','core']::text[], ARRAY['Stand with your feet shoulder-width apart and toes slightly turned out.','Hold the barbell in the crooks of your elbows, with your hands gripping the bar for stability.','Engage your core and keep your chest lifted as you lower your hips back and down into a squat position.','Keep your knees in line with your toes and your weight in your heels.','Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'LSTChY9'),
  ('db-3212', 'basic toe touch (male)', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and your arms by your sides.','Bend forward at the waist, keeping your back straight and your knees slightly bent.','Reach down towards your toes with your hands, keeping your legs as straight as possible.','Pause for a moment at the bottom, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'BbfB8Gb'),
  ('db-0128', 'battling ropes', 'Shoulders', 'Rope', 'delts', ARRAY['forearms','core']::text[], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.','Hold one end of the rope in each hand, with your palms facing each other.','Raise your arms to shoulder height, keeping your elbows slightly bent.','Begin making alternating waves with the ropes by rapidly raising and lowering each arm.','Continue for the desired duration or number of repetitions.']::text[], 'RJa4tCo'),
  ('db-3360', 'bear crawl', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['core','shoulders','triceps']::text[], ARRAY['Start on all fours with your hands directly under your shoulders and your knees directly under your hips.','Lift your knees slightly off the ground, keeping your back flat and your core engaged.','Move your right hand and left foot forward simultaneously, followed by your left hand and right foot.','Continue crawling forward, alternating your hand and foot movements.','Maintain a steady pace and keep your core tight throughout the exercise.','Continue for the desired distance or time.']::text[], '0Yz8WdV'),
  ('db-1259', 'behind head chest stretch', 'Chest', 'Assisted', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Stand tall with your feet shoulder-width apart.','Interlace your fingers behind your head with your elbows pointing outwards.','Slowly squeeze your shoulder blades together and push your chest forward.','Hold the stretch for 15-30 seconds.','Release the stretch and repeat as desired.']::text[], 'QoHIhPl'),
  ('db-0129', 'bench dip (knees bent)', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.','Slide your butt off the bench and straighten your legs in front of you, keeping your heels on the ground.','Bend your elbows and lower your body towards the ground, keeping your back close to the bench.','Pause for a moment at the bottom, then push yourself back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'RrLske5'),
  ('db-1399', 'bench dip on floor', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward.','Slide your butt off the bench, supporting your weight with your hands.','Lower your body by bending your elbows until your upper arms are parallel to the floor.','Push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], '9RT8oQW'),
  ('db-0130', 'bench hip extension', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings']::text[], ARRAY['Sit on a bench with your back against the bench and your feet flat on the ground.','Place your hands on the bench for support.','Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders.','Pause for a moment at the top, then slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'u27Kcdz'),
  ('db-3019', 'bench pull-ups', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Position yourself under a bar or a sturdy horizontal surface that is at chest height.','Grab the bar or surface with an overhand grip, slightly wider than shoulder-width apart.','Hang with your arms fully extended and your body straight.','Pull your chest towards the bar or surface by squeezing your shoulder blades together and bending your elbows.','Continue pulling until your chin is above the bar or surface.','Lower yourself back down to the starting position with control.','Repeat for the desired number of repetitions.']::text[], 'mExgrF9'),
  ('db-3639', 'bent knee lying twist (male)', 'Legs', 'Body Weight', 'glutes', ARRAY['obliques','hip flexors']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Extend your arms out to the sides, perpendicular to your body.','Keeping your knees together, slowly lower them to one side, aiming to touch the ground with your knees.','Pause for a moment, then engage your core and slowly lift your knees back to the starting position.','Repeat the movement to the other side.','Continue alternating sides for the desired number of repetitions.']::text[], '6sYyrRX'),
  ('db-1770', 'biceps leg concentration curl', 'Arms', 'Body Weight', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with your legs spread apart and your feet flat on the ground.','Hold a dumbbell in one hand and place your elbow on the inside of your thigh, just above the knee.','With your palm facing up, curl the dumbbell towards your shoulder while keeping your upper arm stationary.','Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'sJFIDIp'),
  ('db-0139', 'biceps narrow pull-ups', 'Arms', 'Body Weight', 'biceps', ARRAY['forearms','shoulders']::text[], ARRAY['Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart.','Engage your core and pull yourself up towards the bar, focusing on using your biceps to lift your body.','Pause for a moment at the top, then slowly lower yourself back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '50BETrz'),
  ('db-0140', 'biceps pull-up', 'Arms', 'Body Weight', 'biceps', ARRAY['forearms','shoulders']::text[], ARRAY['Hang from a pull-up bar with your palms facing away from you and your hands shoulder-width apart.','Engage your core and pull yourself up by bending your elbows, bringing your chest towards the bar.','Pause at the top of the movement, then slowly lower yourself back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'guT8YnS'),
  ('db-0137', 'body-up', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Start by placing your hands on a raised surface, such as a bench or parallel bars, with your palms facing down and fingers pointing forward.','Extend your legs out in front of you, keeping your heels on the ground and your body straight.','Lower your body by bending your elbows, keeping them close to your sides, until your upper arms are parallel to the ground.','Pause for a moment, then push through your palms to straighten your arms and lift your body back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'U6G2gk9'),
  ('db-3543', 'bodyweight drop jump squat', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Lower your body into a squat position by bending your knees and pushing your hips back.','Jump up explosively, extending your hips, knees, and ankles.','While in mid-air, quickly bring your feet together.','Land softly on the balls of your feet and immediately drop back into a squat position.','Repeat for the desired number of repetitions.']::text[], 'wfotm7S'),
  ('db-3544', 'bodyweight incline side plank', 'Core', 'Body Weight', 'abs', ARRAY['obliques','shoulders']::text[], ARRAY['Start by lying on your side with your legs extended and stacked on top of each other.','Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle.','Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.','Hold this position for the desired amount of time.','Lower your hips back down to the ground and repeat on the other side.']::text[], '5VXmnV5'),
  ('db-1771', 'bodyweight kneeling triceps extension', 'Arms', 'Body Weight', 'triceps', ARRAY['shoulders','chest']::text[], ARRAY['Kneel down on the ground with your knees hip-width apart.','Place your hands on the ground in front of you, shoulder-width apart, fingers pointing forward.','Extend your legs straight behind you, balancing on your toes and hands, forming a straight line from head to heels.','Bend your elbows and lower your upper body towards the ground, keeping your elbows close to your sides.','Pause for a moment at the bottom, then push through your hands to straighten your arms and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 's0HKO2I'),
  ('db-1769', 'bodyweight side lying biceps curl', 'Arms', 'Body Weight', 'biceps', ARRAY['forearms']::text[], ARRAY['Lie on your side with your legs extended and your head supported by your arm.','Hold your upper arm against your side and bend your elbow to curl your forearm towards your shoulder.','Pause for a moment at the top, then slowly lower your forearm back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'gscGLOU'),
  ('db-3168', 'bodyweight squatting row', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart, holding onto a sturdy object or suspension trainer with your arms extended.','Lower your body into a squat position, keeping your back straight and your knees behind your toes.','From the squat position, pull your body up towards the object or suspension trainer, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '3xK09Sk'),
  ('db-3167', 'bodyweight squatting row (with towel)', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a towel in front of you with your palms facing down.','Bend your knees and lower your body into a squat position, keeping your back straight and your chest up.','As you lower into the squat, simultaneously pull the towel towards your chest, squeezing your shoulder blades together.','Pause for a moment at the bottom of the squat, then slowly return to the starting position while extending your arms.','Repeat for the desired number of repetitions.']::text[], 'BReCuOn'),
  ('db-1373', 'bodyweight standing calf raise', 'Legs', 'Body Weight', 'calves', ARRAY['ankles','feet']::text[], ARRAY['Stand with your feet shoulder-width apart, toes pointing forward.','Place your hands on a wall or stable surface for balance.','Slowly raise your heels off the ground, lifting your body weight onto the balls of your feet.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bJYHBIN'),
  ('db-3156', 'bodyweight standing close-grip one arm row', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand with a neutral grip.','Bend forward at the hips, keeping your back straight and your core engaged.','Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'v2DfH14'),
  ('db-3158', 'bodyweight standing close-grip row', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.','Bend forward at the waist, keeping your back straight and your core engaged.','Extend your arms straight in front of you, gripping the bar or handles with a close grip.','Pull the bar or handles towards your body, squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly release and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'tig3PXb'),
  ('db-3162', 'bodyweight standing one arm row', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand.','Bend forward at the hips, keeping your back straight and your core engaged.','Let the dumbbell hang straight down in front of you, with your arm fully extended.','Pull the dumbbell up towards your chest, keeping your elbow close to your body.','Squeeze your shoulder blades together at the top of the movement.','Lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'xbkPfaw'),
  ('db-3161', 'bodyweight standing one arm row (with towel)', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand.','Bend forward at the hips, keeping your back straight and your core engaged.','Pull the towel towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the towel back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'O4oIqQD'),
  ('db-3166', 'bodyweight standing row', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.','Grasp a bar or handles with an overhand grip, palms facing down.','Keep your back straight and core engaged.','Pull the bar or handles towards your body, squeezing your shoulder blades together.','Pause for a moment at the top of the movement.','Slowly release and extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'wd4ds3s'),
  ('db-3165', 'bodyweight standing row (with towel)', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a towel in front of you with both hands.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Pull the towel towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'uTv34oq'),
  ('db-0138', 'bottoms-up', 'Core', 'Body Weight', 'abs', ARRAY['obliques','hip flexors']::text[], ARRAY['Lie flat on your back with your legs extended and your arms by your sides.','Bend your knees and bring them towards your chest, keeping your feet off the ground.','Engaging your abs, lift your hips off the ground, bringing your knees towards your head.','Pause for a moment at the top, then slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'CI6baTY'),
  ('db-1374', 'box jump down with one leg stabilization', 'Legs', 'Body Weight', 'calves', ARRAY['quadriceps','hamstrings','glutes']::text[], ARRAY['Stand in front of a box or platform with your feet shoulder-width apart.','Bend your knees and jump onto the box, landing softly with one foot on the box and the other foot hanging off the edge.','Stabilize yourself on the box with the foot that is on it, while keeping the other foot off the ground.','Hold this position for a few seconds, engaging your calf muscles to maintain balance.','Slowly step down with the foot that is on the box, returning to the starting position.','Repeat the exercise with the other leg.']::text[], 'iPm26QU'),
  ('db-2466', 'bridge - mountain climber (cross body)', 'Core', 'Body Weight', 'abs', ARRAY['glutes','quadriceps','hamstrings','shoulders','triceps']::text[], ARRAY['Start in a high plank position with your hands directly under your shoulders and your body in a straight line.','Engage your core and lift your right foot off the ground, bringing your right knee towards your left elbow.','Return your right foot to the starting position and repeat the movement with your left foot towards your right elbow.','Continue alternating sides, moving at a controlled pace.','Keep your hips level and avoid lifting your hips too high or sagging them too low.','Maintain a steady breathing pattern throughout the exercise.','Repeat for the desired number of repetitions.']::text[], '9c6T1YX'),
  ('db-1160', 'burpee', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves','shoulders','chest']::text[], ARRAY['Start in a standing position with your feet shoulder-width apart.','Lower your body into a squat position by bending your knees and placing your hands on the floor in front of you.','Kick your feet back into a push-up position.','Perform a push-up, keeping your body in a straight line.','Jump your feet back into the squat position.','Jump up explosively, reaching your arms overhead.','Land softly and immediately lower back into a squat position to begin the next repetition.']::text[], 'dK9394r'),
  ('db-0870', 'butt-ups', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors','lower back']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands by your sides, palms facing down.','Engaging your abs, lift your legs off the ground, bringing your knees towards your chest.','At the top of the movement, squeeze your abs and pause for a moment.','Slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'qcNN2FN'),
  ('db-1494', 'butterfly yoga pose', 'Legs', 'Body Weight', 'adductors', ARRAY['hamstrings','groin']::text[], ARRAY['Sit on the floor with your legs extended in front of you.','Bend your knees and bring the soles of your feet together, allowing your knees to fall out to the sides.','Hold onto your ankles or feet with your hands.','Sit up tall and lengthen your spine.','Gently press your knees down towards the floor, feeling a stretch in your inner thighs.','Hold this position for a few breaths.','To release, slowly bring your knees back up and extend your legs.']::text[], 'bWlZvXh'),
  ('db-0148', 'cable alternate shoulder press', 'Shoulders', 'Cable', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and grasp the handles of the cable machine with an overhand grip.','Position your hands at shoulder height, with your palms facing forward.','Keep your core engaged and your back straight.','Press one handle up and forward until your arm is fully extended.','Pause for a moment at the top, then slowly lower the handle back to the starting position.','Repeat with the other arm.','Alternate between arms for the desired number of repetitions.']::text[], 'KHPZL0b'),
  ('db-0149', 'cable alternate triceps extension', 'Arms', 'Cable', 'triceps', ARRAY['shoulders']::text[], ARRAY['Stand facing the cable machine with your feet shoulder-width apart.','Hold the cable handle with your right hand and bring your arm up so that your upper arm is parallel to the ground and your elbow is bent at a 90-degree angle.','Keep your upper arm stationary and extend your forearm backward, fully straightening your arm.','Pause for a moment, then slowly return to the starting position.','Repeat with your left arm.','Continue alternating arms for the desired number of repetitions.']::text[], 'Gchi5Tr'),
  ('db-3235', 'cable assisted inverse leg curl', 'Legs', 'Cable', 'hamstrings', ARRAY['glutes','calves']::text[], ARRAY['Adjust the cable machine so that the ankle attachment is at the lowest setting.','Lie face down on the bench with your legs straight and the ankle attachment secured to your ankles.','Hold onto the handles of the bench for stability.','Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees.','Pause for a moment at the top of the movement, squeezing your hamstrings.','Inhale and slowly lower your legs back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'zHEpuuc'),
  ('db-0150', 'cable bar lateral pulldown', 'Back', 'Cable', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Adjust the cable pulley to a high position and attach a straight bar.','Sit facing the cable machine with your feet flat on the ground and your knees slightly bent.','Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.','Lean back slightly and keep your chest up, maintaining a slight arch in your lower back.','Pull the bar down towards your chest, leading with your elbows and squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, then slowly return the bar to the starting position.','Repeat for the desired number of repetitions.']::text[], 'eYnzaCm'),
  ('db-0151', 'cable bench press', 'Chest', 'Cable', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the cable machine to chest height and attach the handles.','Stand facing away from the machine with your feet shoulder-width apart.','Grasp the handles with an overhand grip and step forward to create tension in the cables.','Position your feet firmly on the ground and engage your core.','Bend your elbows and bring your hands to shoulder level, keeping your elbows at a 90-degree angle.','Push the handles forward, extending your arms fully in front of you.','Pause for a moment, then slowly reverse the movement, bringing your hands back to shoulder level.','Repeat for the desired number of repetitions.']::text[], '7xI5MXA'),
  ('db-1630', 'cable close grip curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Attach a straight bar to a low pulley cable machine.','Stand facing the machine with your feet shoulder-width apart and your knees slightly bent.','Grasp the bar with an underhand grip, hands shoulder-width apart.','Keep your elbows close to your sides and your upper arms stationary throughout the exercise.','Exhale and curl the bar up towards your shoulders, contracting your biceps.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale and slowly lower the bar back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'BCGQ6J5'),
  ('db-1631', 'cable concentration curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench or chair with your feet flat on the floor and your knees slightly bent.','Hold the cable handle with an underhand grip and rest your elbow against the inside of your thigh.','Keeping your upper arm stationary, exhale and curl the cable handle towards your shoulder while contracting your biceps.','Pause for a moment at the top of the movement, then inhale and slowly lower the cable handle back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'NvfE43H'),
  ('db-0152', 'cable concentration extension (on knee)', 'Arms', 'Cable', 'triceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench or chair with your knees bent and feet flat on the ground.','Hold the cable handle with your right hand and place your elbow on the inside of your right knee.','Extend your arm fully, keeping your elbow stationary and close to your knee.','Pause for a moment at the top, then slowly lower your arm back to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'Db7eEgw'),
  ('db-0153', 'cable cross-over lateral pulldown', 'Back', 'Cable', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Attach a cable handle to each side of a cable machine at shoulder height.','Stand in the middle of the machine with your feet shoulder-width apart.','Grasp the handles with an overhand grip and step back to create tension in the cables.','Lean forward slightly from the hips, keeping your back straight and your chest up.','Pull the handles down and across your body, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OQ1otBN'),
  ('db-0154', 'cable cross-over revers fly', 'Shoulders', 'Cable', 'delts', ARRAY['rhomboids','trapezius']::text[], ARRAY['Attach a D-handle to each low pulley cable and stand in the middle of the cable crossover machine.','Grasp the handles with a pronated grip (palms facing down) and take a step forward, positioning your feet shoulder-width apart.','Bend your knees slightly and lean forward at the waist, keeping your back straight and your abs engaged.','With your arms extended out to the sides and slightly bent at the elbows, exhale and squeeze your shoulder blades together as you pull the cables back and upward in a reverse fly motion.','Pause for a moment at the peak contraction, then inhale and slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'aqvSOQE'),
  ('db-0155', 'cable cross-over variation', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Adjust the cable pulleys to chest height.','Stand in the center of the cable machine with one foot in front of the other.','Grasp the handles with your palms facing down and your arms extended out to the sides.','Take a step forward, keeping your arms slightly bent.','With a slight bend in your elbows, bring your hands together in front of your chest.','Pause for a moment, then slowly return your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], '0CXGHya'),
  ('db-0868', 'cable curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand facing the cable machine with your feet shoulder-width apart.','Grasp the cable attachment with an underhand grip, palms facing up.','Keep your elbows close to your sides and your upper arms stationary.','Exhale and curl the cable attachment towards your shoulders, contracting your biceps.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale and slowly lower the cable attachment back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'G08RZcQ'),
  ('db-0157', 'cable deadlift', 'Legs', 'Cable', 'glutes', ARRAY['hamstrings','quadriceps','lower back']::text[], ARRAY['Stand facing the cable machine with your feet shoulder-width apart.','Bend at the hips and knees, lowering your torso until your back is parallel to the ground.','Grasp the cable handles with an overhand grip, keeping your arms straight and your shoulders back.','Engage your glutes and hamstrings to lift the cable handles, extending your hips and standing up straight.','Pause for a moment at the top, then slowly lower the cable handles back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'eGDudUV'),
  ('db-0158', 'cable decline fly', 'Chest', 'Cable', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Adjust the cable machine to a decline position.','Stand facing away from the machine with your feet shoulder-width apart.','Hold the handles with your palms facing forward and your arms extended straight out in front of you.','Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.','Pause for a moment at the fully extended position, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], '7saC5zz'),
  ('db-1260', 'cable decline one arm press', 'Chest', 'Cable', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the cable machine to a decline position.','Stand facing away from the machine and grab the handle with one hand.','Position yourself with your back against the decline bench and your arm extended straight in front of you.','Bend your elbow and lower the handle towards your chest while keeping your upper arm stationary.','Pause for a moment at the bottom, then push the handle back up to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'KHGNa16'),
  ('db-1261', 'cable decline press', 'Chest', 'Cable', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the cable machine to a decline position.','Sit on the decline bench facing the cable machine.','Grasp the handles with an overhand grip and position them at chest level.','Keep your feet flat on the ground and your back firmly against the bench.','Exhale and push the handles away from your body, extending your arms fully.','Pause for a moment at the end of the movement, squeezing your chest muscles.','Inhale and slowly return the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], '2Pya1cP'),
  ('db-0159', 'cable decline seated wide-grip row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Sit on the decline bench facing the cable machine with your feet securely placed on the footrests.','Grasp the cable attachment with a wide overhand grip, palms facing down.','Lean back slightly, keeping your back straight and your core engaged.','Pull the cable towards your lower chest, squeezing your shoulder blades together.','Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'kesXOpB'),
  ('db-1632', 'cable drag curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand facing a cable machine with your feet shoulder-width apart.','Grasp the cable attachment with an underhand grip, palms facing up, and arms fully extended.','Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders by contracting your biceps.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'dXz8zjF'),
  ('db-0160', 'cable floor seated wide-grip row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Sit on the floor with your legs extended and your back straight.','Attach a cable handle to a low pulley and position the cable machine behind you.','Grasp the handle with a wide overhand grip, palms facing down.','Lean back slightly, keeping your back straight and your chest lifted.','Pull the handle towards your waist, squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly release the handle back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'veXwo0D'),
  ('db-0161', 'cable forward raise', 'Shoulders', 'Cable', 'delts', ARRAY['triceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Hold the cable handle with an overhand grip, palms facing down, and your arms fully extended in front of you.','Keeping your arms straight, raise the cable handle up to shoulder level.','Pause for a moment at the top, then slowly lower the cable handle back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'hvHhCv8'),
  ('db-0162', 'cable front raise', 'Shoulders', 'Cable', 'delts', ARRAY['triceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip.','Keep your back straight and your core engaged.','Raise the cable handle in front of you, keeping your arms straight and your palms facing down.','Continue lifting until your arms are parallel to the floor.','Pause for a moment at the top, then slowly lower the cable handle back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'u2X71Np'),
  ('db-0164', 'cable front shoulder raise', 'Shoulders', 'Cable', 'delts', ARRAY['trapezius','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip.','Keep your back straight and your core engaged.','Raise the cable handle in front of you, keeping your arms straight and your palms facing down.','Continue lifting until your arms are parallel to the floor.','Pause for a moment at the top, then slowly lower the cable handle back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'mTT3KLn'),
  ('db-0165', 'cable hammer curl (with rope)', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand upright with your feet shoulder-width apart and a slight bend in your knees.','Hold the cable rope attachment with an underhand grip, palms facing each other, and your arms fully extended.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the cable rope attachment until your biceps are fully contracted and the rope is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the cable rope attachment back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'HPlPoQA'),
  ('db-1722', 'cable high pulley overhead tricep extension', 'Arms', 'Cable', 'triceps', ARRAY['shoulders']::text[], ARRAY['Attach a rope to a high pulley and stand facing away from the machine.','Grasp the rope with both hands and extend your arms overhead.','Keep your elbows close to your head and your upper arms stationary.','Slowly lower the rope behind your head by bending your elbows.','Pause for a moment, then extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], '1xHyxys'),
  ('db-0167', 'cable high row (kneeling)', 'Back', 'Cable', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Attach a straight bar to a cable machine at chest height.','Kneel down in front of the cable machine and grab the bar with an overhand grip, hands shoulder-width apart.','Sit back on your heels, keeping your back straight and your core engaged.','Pull the bar towards your upper abdomen, squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly release the bar back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZSJNetl'),
  ('db-0168', 'cable hip adduction', 'Legs', 'Cable', 'adductors', ARRAY['glutes','quadriceps']::text[], ARRAY['Attach the ankle cuff to your ankle and stand facing the cable machine.','Position yourself far enough away from the machine so that there is tension on the cable.','Place your hands on the machine for support.','Keeping your leg straight, slowly move your leg across your body towards the midline.','Pause for a moment at the end of the movement, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'hBGWILP'),
  ('db-0169', 'cable incline bench press', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Adjust the bench to a 45-degree incline.','Attach the cable handles to the high pulleys.','Sit on the bench facing the cable machine with your feet flat on the ground.','Grasp the handles with an overhand grip and bring them to shoulder height.','Push the handles forward and upward until your arms are fully extended.','Pause for a moment, then slowly lower the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Vh0GsK4'),
  ('db-1318', 'cable incline bench row', 'Back', 'Cable', 'upper back', ARRAY['biceps','rear deltoids']::text[], ARRAY['Set up an incline bench at a 45-degree angle and attach a cable handle to the low pulley.','Sit on the bench facing the cable machine with your feet flat on the floor and your knees slightly bent.','Grasp the cable handle with an overhand grip and extend your arms fully in front of you.','Lean forward from your hips while keeping your back straight and your core engaged.','Pull the cable handle towards your chest by retracting your shoulder blades and bending your elbows.','Squeeze your back muscles at the top of the movement, then slowly extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'yaMIo4D'),
  ('db-0171', 'cable incline fly', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Adjust the cable machine to a low position and attach the handles.','Sit on an incline bench with your back against the pad and feet flat on the floor.','Grasp the handles with an overhand grip and extend your arms straight out in front of you.','Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.','Pause for a moment at the fully extended position, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'tBWXbIT'),
  ('db-0170', 'cable incline fly (on stability ball)', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Set up a stability ball at an incline angle.','Attach the cable handles to the high pulleys of a cable machine.','Sit on the stability ball facing away from the machine, with your feet firmly planted on the ground.','Grasp the cable handles with an overhand grip, palms facing forward.','Lean forward slightly, keeping your back straight and core engaged.','With a controlled motion, bring your arms out to the sides, keeping a slight bend in your elbows.','Continue the motion until your arms are parallel to the ground.','Pause for a moment, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], '27NNGFr'),
  ('db-0172', 'cable incline pushdown', 'Back', 'Cable', 'lats', ARRAY['triceps','shoulders']::text[], ARRAY['Attach a straight bar to a high pulley cable machine.','Stand facing away from the machine with your feet shoulder-width apart.','Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.','Lean forward slightly and keep your back straight.','Pull the bar down towards your thighs by extending your elbows.','Pause for a moment at the bottom, then slowly return the bar to the starting position.','Repeat for the desired number of repetitions.']::text[], '1PK5Uo3'),
  ('db-0173', 'cable incline triceps extension', 'Arms', 'Cable', 'triceps', ARRAY['shoulders']::text[], ARRAY['Adjust the cable machine to a low pulley position.','Attach a straight bar to the cable.','Stand facing away from the machine with your feet shoulder-width apart.','Grasp the bar with an overhand grip and extend your arms straight overhead.','Lean forward slightly, keeping your back straight and core engaged.','Bend your elbows and lower the bar behind your head, keeping your upper arms close to your ears.','Pause for a moment, then extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Hx1WC8I'),
  ('db-0174', 'cable judo flip', 'Core', 'Cable', 'abs', ARRAY['obliques','shoulders']::text[], ARRAY['Stand facing the cable machine with your feet shoulder-width apart.','Hold the cable handle with both hands at chest level, palms facing down.','Engage your core and rotate your torso to the right, pulling the cable across your body.','As you rotate, pivot your back foot and allow your hips to rotate naturally.','Extend your arms fully and finish the movement by flipping the cable handle over your shoulder.','Return to the starting position by reversing the movement, rotating your torso back to the center.','Repeat the movement on the opposite side.','Continue alternating sides for the desired number of repetitions.']::text[], 'MvQPqVW'),
  ('db-0860', 'cable kickback', 'Arms', 'Cable', 'triceps', ARRAY['shoulders']::text[], ARRAY['Stand facing a cable machine with your feet shoulder-width apart.','Hold the cable handle with your right hand and step back to create tension in the cable.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Keep your upper arm close to your body and your elbow bent at a 90-degree angle.','Extend your forearm backward, straightening your arm fully.','Pause for a moment, then slowly return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'HEJ6DIX'),
  ('db-0175', 'cable kneeling crunch', 'Core', 'Cable', 'abs', ARRAY['obliques']::text[], ARRAY['Attach a rope handle to a high pulley and kneel down facing away from the machine.','Hold the rope handle with both hands and place it behind your head, keeping your elbows out to the sides.','Keeping your hips stationary, flex your waist and crunch your torso down towards your thighs.','Pause for a moment at the bottom, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'WW95auq'),
  ('db-3697', 'cable kneeling rear delt row (with rope) (male)', 'Shoulders', 'Cable', 'delts', ARRAY['trapezius','rhomboids','biceps']::text[], ARRAY['Attach a rope handle to a low cable pulley and kneel down facing the machine.','Grasp the rope with a neutral grip (palms facing each other) and extend your arms fully in front of you.','Keeping your back straight and core engaged, pull the rope towards your body by retracting your shoulder blades.','Squeeze your shoulder blades together at the end of the movement and hold for a brief pause.','Slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'G61cXLk'),
  ('db-0176', 'cable kneeling triceps extension', 'Arms', 'Cable', 'triceps', ARRAY['shoulders']::text[], ARRAY['Attach a rope handle to a high pulley and kneel down facing the cable machine.','Grasp the rope with a neutral grip (palms facing each other) and bring your hands to the sides of your head.','Keep your elbows close to your head and your upper arms stationary throughout the exercise.','Extend your forearms by contracting your triceps until your arms are fully extended.','Pause for a moment, then slowly return to the starting position by bending your elbows.','Repeat for the desired number of repetitions.']::text[], 'KWdF2JI'),
  ('db-2330', 'cable lat pulldown full range of motion', 'Back', 'Cable', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Sit on the lat pulldown machine with your knees positioned under the pads.','Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart.','Lean back slightly and keep your chest up, maintaining a slight arch in your lower back.','Pull the bar down towards your upper chest, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'LEprlgG'),
  ('db-0177', 'cable lateral pulldown (with rope attachment)', 'Back', 'Cable', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Attach a rope attachment to the cable machine at a high position.','Stand facing the machine with your feet shoulder-width apart.','Grasp the rope with an overhand grip, palms facing each other.','Keep your back straight and lean slightly back.','Pull the rope down towards your sides, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement.','Slowly release the tension and allow the rope to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'CuaWCmC'),
  ('db-2616', 'cable lateral pulldown with v-bar', 'Back', 'Cable', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Sit down on the cable pulldown machine and grab the v-bar attachment with an overhand grip.','Adjust the knee pad so that your thighs are secured under it.','Keep your back straight and lean back slightly.','Pull the v-bar down towards your upper chest while keeping your elbows close to your body.','Squeeze your back muscles at the bottom of the movement.','Slowly return the v-bar to the starting position and repeat for the desired number of repetitions.']::text[], '4c9BhzB'),
  ('db-0178', 'cable lateral raise', 'Shoulders', 'Cable', 'delts', ARRAY['traps','triceps']::text[], ARRAY['Stand with your feet shoulder-width apart and grasp the cable handles with an overhand grip.','Keep your arms straight and your core engaged.','Raise your arms out to the sides until they are parallel to the floor.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'goJ6ezq'),
  ('db-0179', 'cable low fly', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Attach the handles to the low pulleys of a cable machine and select an appropriate weight.','Stand in the middle of the machine with your feet shoulder-width apart and a slight bend in your knees.','Grasp the handles with an overhand grip and extend your arms out to the sides, keeping a slight bend in your elbows.','Maintaining control, slowly bring your arms forward in a sweeping motion, crossing them in front of your body.','Pause for a moment at the peak of the movement, feeling the stretch in your chest muscles.','Reverse the motion and slowly return your arms to the starting position, keeping tension on your chest muscles throughout.','Repeat for the desired number of repetitions.']::text[], 'FVmZVhk'),
  ('db-0180', 'cable low seated row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Sit on the machine with your feet flat on the footrests and your knees slightly bent.','Grasp the handles with an overhand grip, palms facing down.','Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows.','Pull the handles towards your body, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'hvV79Si'),
  ('db-1634', 'cable lying bicep curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Attach a straight bar to a low pulley cable machine.','Lie face up on a flat bench with your feet flat on the ground.','Grasp the bar with an underhand grip, hands shoulder-width apart.','Extend your arms fully, keeping your elbows close to your sides.','Keeping your upper arms stationary, exhale and curl the bar up towards your shoulders.','Pause for a moment at the top, squeezing your biceps.','Inhale and slowly lower the bar back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'otqIxU4'),
  ('db-0182', 'cable lying close-grip curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Attach a straight bar to a low pulley cable machine.','Lie face up on a flat bench with your feet flat on the ground.','Grasp the bar with an underhand grip, hands shoulder-width apart.','Extend your arms fully, keeping your elbows close to your sides.','Keeping your upper arms stationary, curl the bar towards your chest by contracting your biceps.','Pause for a moment at the top, squeezing your biceps.','Slowly lower the bar back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], '61GrD55'),
  ('db-0184', 'cable lying extension pullover (with rope attachment)', 'Back', 'Cable', 'lats', ARRAY['triceps','shoulders']::text[], ARRAY['Attach a rope to a cable machine and set the pulley at the highest position.','Lie down on a bench with your head towards the cable machine.','Hold the rope with both hands and extend your arms straight up above your chest.','Keeping your arms straight, slowly lower the rope behind your head while maintaining control.','Pause for a moment at the bottom, then slowly raise the rope back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Q2Eu1Ax'),
  ('db-0185', 'cable lying fly', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Attach the handles to the cables and lie flat on a bench with your feet flat on the ground.','Hold the handles with your palms facing each other and your arms extended straight above your chest.','Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest.','Pause for a moment, then squeeze your chest muscles to bring your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'lJJ7Yq8'),
  ('db-0186', 'cable lying triceps extension v. 2', 'Arms', 'Cable', 'triceps', ARRAY['shoulders']::text[], ARRAY['Attach a rope handle to a low pulley cable machine.','Lie down on a flat bench facing up, with your head towards the cable machine.','Grasp the rope handle with both hands, palms facing each other, and extend your arms straight up over your chest.','Keeping your upper arms stationary, slowly lower the rope handle towards your forehead by bending your elbows.','Pause for a moment at the bottom, then extend your arms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'uxJcFUU'),
  ('db-0188', 'cable middle fly', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Attach cables to both sides of a cable machine at chest height.','Stand in the center of the machine with one foot slightly in front of the other.','Grasp the handles with an overhand grip and extend your arms out to the sides.','Keep a slight bend in your elbows and maintain a slight forward lean.','Engage your chest muscles and bring your arms forward in a sweeping motion.','Pause for a moment at the center, then slowly return your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'xLYSdtg'),
  ('db-0189', 'cable one arm bent over row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand facing a cable machine with your feet shoulder-width apart.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Grasp the cable handle with one hand, palm facing inward, and extend your arm fully.','Pull the cable handle towards your body, keeping your elbow close to your side, until your hand reaches your lower chest.','Pause for a moment, then slowly extend your arm back to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'EIsE3u8'),
  ('db-0190', 'cable one arm curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand facing the cable machine with your feet shoulder-width apart.','Grasp the cable handle with an underhand grip, palm facing up.','Keep your elbow close to your side and slowly curl your forearm up towards your shoulder.','Pause for a moment at the top, then slowly lower your forearm back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'YTur5nR'),
  ('db-1262', 'cable one arm decline chest fly', 'Chest', 'Cable', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Attach a D-handle to a low pulley cable machine and set the bench to a decline angle.','Lie down on the bench with your head towards the machine and grab the handle with your right hand.','Extend your arm straight up above your chest, keeping a slight bend in your elbow.','With a controlled motion, lower your arm out to the side until your hand is in line with your shoulder.','Pause for a moment, then reverse the motion and bring your arm back to the starting position.','Repeat for the desired number of repetitions, then switch to your left arm and repeat the exercise.']::text[], 'w4dLzSx'),
  ('db-1263', 'cable one arm fly on exercise ball', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back straight.','Hold a cable handle in one hand and extend your arm out to the side, parallel to the ground.','Keep your elbow slightly bent and your palm facing forward.','Slowly bring your arm across your body, squeezing your chest muscles.','Pause for a moment at the end of the movement, then slowly return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'hHy8tQG'),
  ('db-1264', 'cable one arm incline fly on exercise ball', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back against an incline bench.','Hold a cable handle in one hand with your arm extended and palm facing inward.','Keeping a slight bend in your elbow, slowly lower your arm out to the side until your hand is in line with your shoulder.','Pause for a moment, then squeeze your chest muscles to bring your arm back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'P14Dz9D'),
  ('db-1265', 'cable one arm incline press', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Adjust the cable machine to a low pulley position.','Sit on an incline bench facing away from the cable machine.','Grasp the handle with one hand and bring it up to shoulder height.','Position your feet firmly on the ground and maintain a stable position.','Press the handle forward and upward, extending your arm fully.','Pause for a moment at the top, then slowly lower the handle back to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'GKEH6jj'),
  ('db-1266', 'cable one arm incline press on exercise ball', 'Chest', 'Cable', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back resting against an incline bench.','Hold a cable handle in one hand and position your arm at a 90-degree angle with your elbow bent.','Press the cable handle forward and upward, extending your arm fully.','Pause for a moment at the top, then slowly lower the cable handle back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], '6t00BsF'),
  ('db-0191', 'cable one arm lateral bent-over', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','trapezius']::text[], ARRAY['Stand with your feet shoulder-width apart, facing a cable machine.','Grasp the handle with one hand and step back to create tension on the cable.','Bend forward at the waist, keeping your back straight and your core engaged.','Extend your arm out to the side, parallel to the ground, with a slight bend in your elbow.','Slowly bring your arm back to the starting position, maintaining control throughout the movement.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'dB07vDu'),
  ('db-0192', 'cable one arm lateral raise', 'Shoulders', 'Cable', 'delts', ARRAY['traps','triceps']::text[], ARRAY['Stand with your feet shoulder-width apart, facing the cable machine.','Hold the cable handle with one hand, palm facing down, and stand far enough away from the machine so that there is tension on the cable.','Keep your arm straight and slowly raise it out to the side until it is parallel to the ground.','Pause for a moment at the top, then slowly lower your arm back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'wEulIzp'),
  ('db-1633', 'cable one arm preacher curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the cable machine so that the preacher curl pad is at chest height.','Stand facing the cable machine with your feet shoulder-width apart.','Grasp the cable handle with an underhand grip and position your upper arm against the preacher curl pad.','Keep your back straight and your core engaged.','Slowly curl the cable handle towards your shoulder, keeping your upper arm against the pad.','Pause for a moment at the top of the movement, squeezing your biceps.','Slowly lower the cable handle back to the starting position.','Repeat for the desired number of repetitions.','Switch arms and repeat the exercise.']::text[], 'eHBlPsa'),
  ('db-1267', 'cable one arm press on exercise ball', 'Chest', 'Cable', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back straight.','Hold a cable handle in one hand and position your arm at chest height, elbow bent.','Place your other hand on your hip for stability.','Press the cable handle forward, extending your arm fully.','Pause for a moment, then slowly return to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'MKIelrR'),
  ('db-3563', 'cable one arm pulldown', 'Back', 'Cable', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Attach a single handle to a high pulley cable machine.','Stand facing the machine with your feet shoulder-width apart.','Grasp the handle with an overhand grip and extend your arm fully.','Keep your back straight and your core engaged.','Pull the handle down towards your side while keeping your elbow close to your body.','Pause for a moment at the bottom of the movement, squeezing your lat muscle.','Slowly release the handle back to the starting position.','Repeat for the desired number of repetitions.','Switch sides and repeat the exercise with the other arm.']::text[], 'U5INZY6'),
  ('db-1635', 'cable one arm reverse preacher curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the cable machine so that the pulley is at the lowest position.','Stand facing the cable machine with your feet shoulder-width apart.','Grasp the cable handle with an underhand grip and position your upper arm against the preacher bench pad.','Keep your back straight and your core engaged throughout the exercise.','Slowly curl your forearm towards your bicep, keeping your upper arm stationary against the pad.','Pause for a moment at the top of the movement, squeezing your bicep.','Slowly lower the cable handle back to the starting position.','Repeat for the desired number of repetitions.','Switch arms and repeat the exercise.']::text[], 'ZXnjcOQ'),
  ('db-0193', 'cable one arm straight back high row (kneeling)', 'Back', 'Cable', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Attach a handle to a cable machine at waist height.','Kneel down facing the cable machine and grab the handle with one hand.','Keep your back straight and your core engaged.','Pull the handle towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top of the movement.','Slowly release the handle back to the starting position.','Repeat for the desired number of repetitions.','Switch sides and repeat the exercise with the other arm.']::text[], 'WrYPP2g'),
  ('db-1723', 'cable one arm tricep pushdown', 'Arms', 'Cable', 'triceps', ARRAY['forearms']::text[], ARRAY['Stand facing a cable machine with a straight bar attachment at chest height.','Grasp the bar with an overhand grip and step back to create tension in the cable.','Position your feet shoulder-width apart and slightly bend your knees.','Keep your back straight and core engaged throughout the exercise.','Start with your arm fully extended and perpendicular to the floor.','Keeping your upper arm stationary, exhale and push the bar down until your arm is fully extended.','Pause for a moment, then inhale and slowly return to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'qRZ5S1N'),
  ('db-1636', 'cable overhead curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms','shoulders']::text[], ARRAY['Attach a straight bar to a high pulley cable machine.','Stand facing the machine with your feet shoulder-width apart.','Grasp the bar with an underhand grip, hands shoulder-width apart.','Keep your elbows close to your sides and your upper arms stationary.','Exhale and curl the bar down towards your forehead, keeping your upper arms stationary.','Pause for a moment at the bottom of the movement, squeezing your biceps.','Inhale and slowly return the bar to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'wDUqY2u'),
  ('db-1637', 'cable overhead curl on exercise ball', 'Arms', 'Cable', 'biceps', ARRAY['forearms','shoulders']::text[], ARRAY['Sit on an exercise ball and hold the cable handle with an underhand grip.','Extend your arms fully overhead, keeping your elbows close to your ears.','Slowly curl the cable down towards your forehead, keeping your upper arms stationary.','Pause for a moment at the bottom of the movement, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ioTf098'),
  ('db-0194', 'cable overhead triceps extension (rope attachment)', 'Arms', 'Cable', 'triceps', ARRAY['shoulders']::text[], ARRAY['Attach a rope to a cable machine at a high position.','Stand facing away from the machine with your feet shoulder-width apart.','Grasp the rope with both hands, palms facing each other, and bring your hands above your head.','Keep your upper arms close to your head and your elbows pointing forward.','Slowly lower the rope behind your head by bending your elbows.','Pause for a moment, then extend your arms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], '2IxROQ1'),
  ('db-1319', 'cable palm rotational row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Attach a handle to a cable machine at waist height.','Stand facing the machine with your feet shoulder-width apart.','Grasp the handle with an overhand grip, palms facing down.','Step back to create tension on the cable, keeping your back straight and knees slightly bent.','Pull the handle towards your body, rotating your palms to face upwards as you do so.','Squeeze your shoulder blades together at the end of the movement.','Slowly release the handle back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OmQ8w0p'),
  ('db-0195', 'cable preacher curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the cable machine so that the preacher curl pad is at chest height.','Sit on the preacher curl bench and place your upper arms on the pad, gripping the cable attachment with an underhand grip.','Keep your back straight and your elbows tucked in at your sides.','Slowly curl the cable attachment up towards your shoulders, squeezing your biceps at the top of the movement.','Pause for a moment, then slowly lower the cable attachment back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'P2lNrGL'),
  ('db-1268', 'cable press on exercise ball', 'Chest', 'Cable', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your knees at a 90-degree angle.','Hold the cable handles at chest height with your palms facing down and your elbows bent.','Engage your core and press the cable handles forward until your arms are fully extended.','Pause for a moment, then slowly release the tension and bring the cable handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'vAwm6rK'),
  ('db-0196', 'cable pull through (with rope)', 'Legs', 'Cable', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Stand facing away from the cable machine with your feet shoulder-width apart.','Grab the rope attachment with both hands and step forward, creating tension in the cable.','Bend at the hips and lower your upper body until it is parallel to the ground, keeping your back straight.','Engage your glutes and hamstrings to pull your body back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OM46QHm'),
  ('db-0198', 'cable pulldown', 'Back', 'Cable', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the cable pulldown machine so that the seat is at a comfortable height and the knee pad is secured.','Sit on the seat with your back straight and your feet flat on the ground.','Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart.','Lean back slightly and engage your core.','Pull the cable bar down towards your chest, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'RVwzP10'),
  ('db-0197', 'cable pulldown (pro lat bar)', 'Back', 'Cable', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the seat height so that your thighs are parallel to the ground and your feet are flat on the floor.','Grasp the lat bar with an overhand grip, slightly wider than shoulder-width apart.','Sit down and lean back slightly, keeping your chest up and your back straight.','Pull the bar down towards your chest, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'qdRxqCj'),
  ('db-1638', 'cable pulldown bicep curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Attach a straight bar to the cable machine at the highest setting.','Stand facing the machine with your feet shoulder-width apart.','Grasp the bar with an underhand grip, hands shoulder-width apart.','Keep your elbows close to your sides and your upper arms stationary.','Exhale and slowly curl the bar down towards your thighs, keeping your wrists straight.','Pause for a moment at the bottom of the movement, squeezing your biceps.','Inhale and slowly return the bar to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'QTXKWPh'),
  ('db-0201', 'cable pushdown', 'Arms', 'Cable', 'triceps', ARRAY['forearms']::text[], ARRAY['Attach a straight bar to a high pulley cable machine.','Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.','Grasp the bar with an overhand grip, hands shoulder-width apart.','Keep your elbows close to your sides and your upper arms stationary.','Exhale and push the bar down until your elbows are fully extended.','Pause for a moment, then inhale and slowly return the bar to the starting position.','Repeat for the desired number of repetitions.']::text[], '3ZflifB'),
  ('db-0199', 'cable pushdown (straight arm) v. 2', 'Back', 'Cable', 'lats', ARRAY['triceps','shoulders']::text[], ARRAY['Attach a straight bar to a high pulley cable machine.','Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.','Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down.','Engage your core and keep your back straight as you exhale and push the bar down towards your thighs.','Pause for a moment at the bottom, then slowly return the bar to the starting position while inhaling.','Repeat for the desired number of repetitions.']::text[], 'PskORrA'),
  ('db-0200', 'cable pushdown (with rope attachment)', 'Arms', 'Cable', 'triceps', ARRAY['forearms']::text[], ARRAY['Attach a rope attachment to a high pulley on a cable machine.','Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.','Grasp the rope with an overhand grip, palms facing each other.','Keep your elbows close to your sides and your upper arms stationary throughout the exercise.','Exhale and push the rope downward by extending your elbows until your arms are fully extended.','Pause for a moment, then inhale and slowly return to the starting position by allowing your elbows to flex.','Repeat for the desired number of repetitions.']::text[], 'dU605di'),
  ('db-0202', 'cable rear delt row (stirrups)', 'Shoulders', 'Cable', 'delts', ARRAY['trapezius','rhomboids','biceps']::text[], ARRAY['Attach a stirrup handle to a low cable pulley and stand facing the machine.','Grasp the handle with your left hand and take a step back with your right foot, positioning your body at a slight angle.','Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.','With your left arm extended and your palm facing down, pull the handle towards your chest by retracting your shoulder blade.','Pause for a moment at the top of the movement, squeezing your shoulder blade.','Slowly release the handle back to the starting position and repeat for the desired number of repetitions.','Switch sides and repeat the exercise with your right arm.']::text[], 'yUdIGNs'),
  ('db-0203', 'cable rear delt row (with rope)', 'Shoulders', 'Cable', 'delts', ARRAY['trapezius','rhomboids','biceps']::text[], ARRAY['Attach a rope handle to a low pulley cable machine.','Stand facing the machine with your feet shoulder-width apart.','Grasp the rope handle with an overhand grip, palms facing each other.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Keep your elbows slightly bent and pull the rope towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'wqNPGCg'),
  ('db-0204', 'cable rear drive', 'Arms', 'Cable', 'triceps', ARRAY['shoulders','back']::text[], ARRAY['Attach a handle to a low pulley cable machine and stand facing away from the machine.','Grasp the handle with an overhand grip and extend your arms straight out in front of you.','Keeping your elbows stationary, pull the handle back towards your body, squeezing your triceps at the end of the movement.','Slowly return the handle to the starting position and repeat for the desired number of repetitions.']::text[], 'c3QQLPi'),
  ('db-0205', 'cable rear pulldown', 'Back', 'Cable', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Adjust the cable machine so that the pulley is at the highest position.','Sit facing the machine with your feet flat on the ground and your knees slightly bent.','Grasp the cable attachment with an overhand grip, hands slightly wider than shoulder-width apart.','Lean back slightly, keeping your back straight and your chest up.','Pull the cable attachment down towards your chest, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, then slowly release the cable back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'SpsOSXk'),
  ('db-0873', 'cable reverse crunch', 'Core', 'Cable', 'abs', ARRAY['hip flexors']::text[], ARRAY['Attach a cable to a low pulley and lie down facing up on a mat.','Hold the cable with both hands and extend your arms straight up towards the ceiling.','Bend your knees and lift your legs up, bringing your thighs towards your chest.','While keeping your upper body stable, curl your pelvis up towards your chest, lifting your hips off the mat.','Pause for a moment at the top, then slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'RqOtqD7'),
  ('db-0206', 'cable reverse curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Attach a straight bar to a low pulley cable machine.','Stand facing the machine with your feet shoulder-width apart and your knees slightly bent.','Grasp the bar with an underhand grip, hands shoulder-width apart.','Keep your elbows close to your sides and your upper arms stationary throughout the exercise.','Exhale and curl the bar up towards your shoulders, contracting your biceps.','Pause for a moment at the top, squeezing your biceps.','Inhale and slowly lower the bar back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'eOG0r6v'),
  ('db-2406', 'cable reverse grip triceps pushdown (sz-bar) (with arm blaster)', 'Arms', 'Cable', 'triceps', ARRAY['forearms']::text[], ARRAY['Attach a straight bar to the cable machine at the highest setting.','Stand facing the cable machine with your feet shoulder-width apart.','Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart.','Keep your elbows close to your sides and your upper arms stationary throughout the exercise.','Engage your triceps and slowly push the bar down until your arms are fully extended.','Pause for a moment at the bottom, then slowly return the bar to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ThKP69G'),
  ('db-1413', 'cable reverse one arm curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand facing a cable machine with your feet shoulder-width apart.','Grasp the cable handle with an underhand grip, palm facing down.','Keep your elbow close to your side and slowly curl your forearm up towards your shoulder.','Pause for a moment at the top, then slowly lower your forearm back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'gVlnLIJ'),
  ('db-0209', 'cable reverse preacher curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the cable machine so that the preacher curl pad is at chest height.','Sit on the preacher curl bench and place your upper arms on the pad, with your palms facing down and your elbows fully extended.','Grab the cable handles with an underhand grip, shoulder-width apart.','Keeping your upper arms stationary, exhale and curl the handles towards your shoulders, contracting your biceps.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale and slowly lower the handles back to the starting position, fully extending your elbows.','Repeat for the desired number of repetitions.']::text[], 'IwX5NqK'),
  ('db-0210', 'cable reverse wrist curl', 'Arms', 'Cable', 'forearms', ARRAY['forearms','wrists']::text[], ARRAY['Attach a cable to a low pulley and sit on a bench facing the cable machine.','Grasp the cable handle with an overhand grip, palms facing down.','Rest your forearms on your thighs, with your wrists hanging off the edge.','Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.','Pause for a moment at the top, then inhale and slowly lower your wrists back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'eYmsEPR'),
  ('db-0207', 'cable reverse-grip pushdown', 'Arms', 'Cable', 'triceps', ARRAY['forearms']::text[], ARRAY['Attach a straight bar to a high pulley cable machine.','Stand facing the machine with your feet shoulder-width apart.','Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart.','Keep your elbows close to your sides and your upper arms stationary throughout the exercise.','Using your triceps, push the bar down until your arms are fully extended and your triceps are contracted.','Pause for a moment, then slowly return the bar to the starting position.','Repeat for the desired number of repetitions.']::text[], 'VjYliFZ'),
  ('db-0208', 'cable reverse-grip straight back seated high row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Sit on the seat facing the cable machine with your feet flat on the floor.','Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart.','Keep your back straight and lean slightly forward from your hips.','Pull the cable towards your torso by retracting your shoulder blades and squeezing your back muscles.','Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'PNtsX17'),
  ('db-1320', 'cable rope crossover seated row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Sit on the rowing machine with your feet flat on the footrests and your knees slightly bent.','Grasp the cable ropes with an overhand grip, palms facing each other.','Lean back slightly, keeping your back straight and your core engaged.','Pull the cable ropes towards your chest, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'UFGF6gk'),
  ('db-1321', 'cable rope elevated seated row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Sit on the elevated seat facing the cable machine.','Grab the cable rope handles with an overhand grip, palms facing each other.','Keep your back straight and lean slightly back, maintaining a slight bend in your knees.','Pull the cable towards your body by retracting your shoulder blades and squeezing your back muscles.','Pause for a moment at the fully contracted position.','Slowly release the tension and extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'c8oybX6'),
  ('db-1322', 'cable rope extension incline bench row', 'Back', 'Cable', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Set up an incline bench at a 45-degree angle and attach a cable machine to the low pulley.','Attach a rope handle to the cable machine and sit on the incline bench facing the machine.','Grab the rope handle with an overhand grip and lean forward, keeping your back straight.','Extend your arms fully, pulling the rope towards your upper chest while keeping your elbows close to your body.','Squeeze your shoulder blades together at the end of the movement.','Slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'MgKwAAo'),
  ('db-1639', 'cable rope hammer preacher curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Attach a rope attachment to a low pulley cable machine.','Stand facing the machine with your feet shoulder-width apart.','Grasp the rope with a neutral grip (palms facing each other).','Position your upper arms against the preacher bench pad, keeping your elbows slightly bent.','Keeping your upper arms stationary, exhale and curl the rope towards your shoulders by contracting your biceps.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly lower the rope back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'PcPe0P5'),
  ('db-1724', 'cable rope high pulley overhead tricep extension', 'Arms', 'Cable', 'triceps', ARRAY['shoulders']::text[], ARRAY['Attach a rope to a high pulley and adjust the weight accordingly.','Stand facing away from the pulley machine with your feet shoulder-width apart.','Grasp the rope with both hands, palms facing down, and bring your hands above your head.','Keep your upper arms close to your head and perpendicular to the floor.','Slowly lower the rope behind your head by bending your elbows.','Pause for a moment, then extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'NN8nSNT'),
  ('db-1725', 'cable rope incline tricep extension', 'Arms', 'Cable', 'triceps', ARRAY['shoulders']::text[], ARRAY['Attach a rope to a high pulley and adjust the incline bench to a comfortable angle.','Stand facing away from the pulley with your feet shoulder-width apart.','Grasp the rope with an overhand grip and extend your arms straight overhead.','Keep your elbows close to your head and your upper arms stationary throughout the exercise.','Lower the rope behind your head by bending your elbows until your forearms touch your biceps.','Pause for a moment, then extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZujAdR9'),
  ('db-1726', 'cable rope lying on floor tricep extension', 'Arms', 'Cable', 'triceps', ARRAY['shoulders']::text[], ARRAY['Attach a rope to a cable machine and set it to the lowest position.','Lie on the floor facing up, with your head towards the cable machine.','Hold the rope with both hands, palms facing each other, and extend your arms straight up towards the ceiling.','Keep your upper arms stationary and slowly lower the rope towards your forehead, bending your elbows.','Pause for a moment, then extend your arms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'U3ffHlY'),
  ('db-1640', 'cable rope one arm hammer preacher curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Attach a rope handle to a low pulley cable machine.','Stand facing the machine with your feet shoulder-width apart.','Grasp the rope handle with an underhand grip, palms facing up.','Position your upper arm against the preacher bench pad, keeping your elbow slightly bent.','Keep your back straight and your core engaged throughout the exercise.','Slowly curl the rope handle towards your shoulder, keeping your upper arm stationary.','Squeeze your biceps at the top of the movement, then slowly lower the rope handle back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], '4hATdoB'),
  ('db-1323', 'cable rope seated row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Sit on the rowing machine with your feet flat on the footrests and knees slightly bent.','Grasp the cable ropes with an overhand grip, palms facing each other.','Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows.','Pull the cable ropes towards your body, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'SJqRxOt'),
  ('db-0211', 'cable russian twists (on stability ball)', 'Core', 'Cable', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.','Hold the cable handle with both hands and extend your arms straight out in front of you.','Lean back slightly while keeping your back straight and your core engaged.','Twist your torso to the right, bringing the cable handle towards your right hip.','Pause for a moment, then twist your torso to the left, bringing the cable handle towards your left hip.','Continue alternating twists for the desired number of repetitions.']::text[], 'd9Xaxq6'),
  ('db-2144', 'cable seated chest press', 'Chest', 'Cable', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Adjust the seat height and cable handles to a comfortable position.','Sit on the bench with your back straight and feet flat on the floor.','Grasp the cable handles with an overhand grip at shoulder height.','Push the handles forward and away from your body, extending your arms fully.','Pause for a moment, then slowly bring the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'nIR4Rwl'),
  ('db-0212', 'cable seated crunch', 'Core', 'Cable', 'abs', ARRAY['obliques']::text[], ARRAY['Sit on a cable machine with your feet flat on the ground and your knees bent.','Hold the cable handle with both hands and position it behind your head.','Engage your abs and slowly curl your upper body forward, bringing your chest towards your knees.','Pause for a moment at the top, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], '8xUv4J7'),
  ('db-1641', 'cable seated curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a cable machine with your feet flat on the ground and your back straight.','Grasp the cable attachment with an underhand grip, palms facing up, and your arms fully extended.','Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders, contracting your biceps.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], '8oYqOt9'),
  ('db-0213', 'cable seated high row (v-bar)', 'Back', 'Cable', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Sit on the cable machine with your feet flat on the floor and your knees slightly bent.','Grasp the v-bar attachment with an overhand grip, palms facing each other, and your hands shoulder-width apart.','Keep your back straight and lean slightly forward from the hips.','Pull the v-bar towards your torso by retracting your shoulder blades and squeezing your back muscles.','Pause for a moment at the peak of the contraction, then slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'pwt0pnM'),
  ('db-0214', 'cable seated one arm alternate row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Sit on a bench facing a cable machine with your feet flat on the ground and knees slightly bent.','Grasp the handle with one hand and keep your arm fully extended in front of you.','Pull the handle towards your body, retracting your shoulder blade and keeping your elbow close to your side.','Pause for a moment at the top of the movement, squeezing your back muscles.','Slowly release the handle back to the starting position.','Repeat with the other arm.','Alternate between arms for the desired number of repetitions.']::text[], 'vpp9Ku2'),
  ('db-1642', 'cable seated one arm concentration curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with your feet flat on the floor and your back straight.','Hold a cable handle with one hand and place your elbow on the inside of your thigh, just above the knee.','Keep your upper arm stationary and curl the cable handle towards your shoulder while exhaling.','Pause for a moment at the top of the movement, squeezing your biceps.','Slowly lower the cable handle back to the starting position while inhaling.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'rZ80Gbp'),
  ('db-1643', 'cable seated overhead curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms','shoulders']::text[], ARRAY['Sit on a bench facing the cable machine with your feet flat on the ground.','Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart.','Keep your upper arms stationary and your elbows close to your sides.','Exhale and curl the cable attachment towards your shoulders, contracting your biceps.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'DpWMFP5'),
  ('db-0215', 'cable seated rear lateral raise', 'Shoulders', 'Cable', 'delts', ARRAY['traps','rhomboids']::text[], ARRAY['Sit on a bench facing the cable machine with your feet flat on the ground.','Grasp the cable handles with an overhand grip and extend your arms straight in front of you.','Keeping your arms straight, slowly raise them out to the sides until they are parallel to the floor.','Pause for a moment at the top, then slowly lower your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'x825CZm'),
  ('db-0861', 'cable seated row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.','Grasp the handles with an overhand grip, keeping your back straight and your shoulders relaxed.','Pull the handles towards your body, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'fUBheHs'),
  ('db-0216', 'cable seated shoulder internal rotation', 'Shoulders', 'Cable', 'delts', ARRAY['rotator cuff','triceps']::text[], ARRAY['Sit on a bench or chair facing the cable machine with your feet flat on the ground.','Hold the cable handle with your arm extended straight out in front of you, parallel to the ground.','Keep your elbow slightly bent and your shoulder blades pulled back and down.','Slowly rotate your arm inward, bringing the cable handle towards the center of your body.','Pause for a moment at the end of the movement, then slowly return to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'YPoVrBi'),
  ('db-2399', 'cable seated twist', 'Core', 'Cable', 'abs', ARRAY['obliques']::text[], ARRAY['Sit on a cable machine with your feet flat on the ground and your knees slightly bent.','Hold the cable handle with both hands and extend your arms straight in front of you.','Keeping your core engaged, slowly rotate your torso to one side, pulling the cable across your body.','Pause for a moment at the end of the range of motion, then slowly rotate back to the starting position.','Repeat on the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'UEjSrKI'),
  ('db-0218', 'cable seated wide-grip row', 'Back', 'Cable', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.','Grasp the handle with a wide overhand grip, palms facing down.','Keep your back straight and lean slightly forward from the hips.','Pull the handle towards your lower chest, squeezing your shoulder blades together.','Pause for a moment at the peak of the contraction.','Slowly release the handle back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'qcY50ZD'),
  ('db-0219', 'cable shoulder press', 'Shoulders', 'Cable', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Adjust the cable machine so that the handles are at shoulder height.','Stand facing away from the machine with your feet shoulder-width apart.','Grasp the handles with an overhand grip and bring them up to shoulder level, with your elbows bent and pointing outwards.','Press the handles upwards until your arms are fully extended overhead.','Pause for a moment at the top, then slowly lower the handles back down to shoulder level.','Repeat for the desired number of repetitions.']::text[], 'PzQanLE'),
  ('db-0220', 'cable shrug', 'Back', 'Cable', 'traps', ARRAY['shoulders']::text[], ARRAY['Stand facing the cable machine with your feet shoulder-width apart.','Grasp the cable handles with an overhand grip and let your arms hang down in front of you.','Keeping your arms straight, shrug your shoulders up towards your ears.','Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Eg98Ft9'),
  ('db-0222', 'cable side bend', 'Core', 'Cable', 'abs', ARRAY['obliques']::text[], ARRAY['Stand with your feet shoulder-width apart and grasp the cable handle with one hand.','Keep your back straight and your core engaged.','Slowly bend sideways at the waist, lowering the cable handle towards your knee.','Pause for a moment, then return to the starting position.','Repeat on the other side.','Alternate sides for the desired number of repetitions.']::text[], 'wPypxFY'),
  ('db-0221', 'cable side bend crunch (bosu ball)', 'Core', 'Cable', 'abs', ARRAY['obliques']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a cable handle in one hand.','Place the other hand on your hip.','Engage your core and slowly bend sideways towards the hand holding the cable, keeping your back straight.','Pause for a moment at the bottom of the movement, then slowly return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'qatbkEd'),
  ('db-0223', 'cable side crunch', 'Core', 'Cable', 'abs', ARRAY['obliques']::text[], ARRAY['Attach a cable handle to a low pulley and stand sideways to the machine.','Grasp the handle with the hand furthest from the machine and place your other hand on your hip.','Keep your feet shoulder-width apart and your knees slightly bent.','With your abs engaged, bend sideways at the waist, bringing your elbow down towards your hip.','Pause for a moment at the bottom, then slowly return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'q2ADGqV'),
  ('db-1717', 'cable squat row (with rope attachment)', 'Back', 'Cable', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Attach a rope to a cable machine at waist height.','Stand facing the cable machine with your feet shoulder-width apart.','Bend your knees and lower your body into a squat position, keeping your back straight and chest up.','Grasp the rope with an overhand grip, with your hands shoulder-width apart.','Engage your core and pull the rope towards your body, squeezing your shoulder blades together.','Keep your elbows close to your body and continue pulling until your hands reach your chest.','Pause for a moment at the top of the movement, then slowly release the rope and extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'f7fnAIB'),
  ('db-1644', 'cable squatting curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Attach a cable handle to the lowest setting on a cable machine.','Stand facing the machine with your feet shoulder-width apart.','Hold the cable handle with an underhand grip, palms facing up, and arms fully extended.','Lower your body into a squat position, keeping your back straight and knees behind your toes.','As you squat down, curl the cable handle towards your shoulders, keeping your elbows close to your sides.','Pause for a moment at the top of the curl, squeezing your biceps.','Slowly lower the cable handle back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], '3XFdb1Z'),
  ('db-0224', 'cable standing back wrist curl', 'Arms', 'Cable', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Stand facing a cable machine with your feet shoulder-width apart.','Hold the cable handle with an overhand grip, palms facing down.','Keep your arms straight and your elbows close to your sides.','Slowly curl your wrists upward, bringing the cable handle towards your body.','Pause for a moment at the top, then slowly lower the cable handle back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'VhX2JdE'),
  ('db-1375', 'cable standing calf raise', 'Legs', 'Cable', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand facing a cable machine with your feet shoulder-width apart.','Hold onto the cable machine handles or attach a cable ankle strap to your ankles.','Raise your heels off the ground by extending your ankles as high as possible.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'yl2IYyy'),
  ('db-0225', 'cable standing cross-over high reverse fly', 'Shoulders', 'Cable', 'delts', ARRAY['trapezius','rhomboids','rear deltoids']::text[], ARRAY['Attach a D-handle to each side of a cable machine at shoulder height.','Stand in the middle of the cable machine with your feet shoulder-width apart.','Grasp the handles with an overhand grip and extend your arms out to the sides, palms facing forward.','Keep a slight bend in your elbows and maintain a straight back throughout the exercise.','Engage your shoulder muscles and squeeze your shoulder blades together as you pull the handles towards the front of your body.','Pause for a moment at the peak of the movement, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'P5p0j8B'),
  ('db-0226', 'cable standing crunch', 'Core', 'Cable', 'abs', ARRAY['obliques']::text[], ARRAY['Attach a cable handle to a high pulley and stand facing away from the machine.','Hold the handle with both hands and place it behind your head, keeping your elbows bent.','Stand with your feet shoulder-width apart and your knees slightly bent.','Keeping your abs engaged, exhale and crunch your torso down towards your knees, bringing your elbows towards your thighs.','Pause for a moment at the bottom of the movement, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'jpgqxiS'),
  ('db-0874', 'cable standing crunch (with rope attachment)', 'Core', 'Cable', 'abs', ARRAY['obliques']::text[], ARRAY['Attach a rope to a cable machine at chest height.','Stand facing away from the machine with your feet shoulder-width apart.','Hold the rope with both hands and bring it behind your head, keeping your elbows bent.','Engage your abs and slowly crunch your torso forward, bringing your elbows towards your knees.','Pause for a moment at the top of the crunch, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'XU3ePuv'),
  ('db-0227', 'cable standing fly', 'Chest', 'Cable', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Attach the handles to the cables at chest height.','Stand with your feet shoulder-width apart, facing away from the cable machine.','Grasp the handles with an overhand grip, palms facing forward.','Step forward slightly to create tension in the cables.','Keep your core engaged and your back straight throughout the exercise.','With a slight bend in your elbows, slowly bring your arms forward and together in front of your chest.','Squeeze your chest muscles at the peak of the movement.','Slowly reverse the movement, returning your arms to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Pr9Rhf4'),
  ('db-0228', 'cable standing hip extension', 'Legs', 'Cable', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Attach a cable to a low pulley and stand facing away from the machine.','Place the cable around your ankle and stand with your feet shoulder-width apart.','Keep your core engaged and your back straight throughout the exercise.','Slowly extend your leg straight back, squeezing your glutes at the top of the movement.','Pause for a moment, then return to the starting position.','Repeat for the desired number of repetitions.','Switch sides and repeat with the other leg.']::text[], 'Kpajagk'),
  ('db-0229', 'cable standing inner curl', 'Arms', 'Cable', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand facing a cable machine with your feet shoulder-width apart.','Grasp the cable handle with an underhand grip, palms facing up.','Keep your elbows close to your sides and your upper arms stationary.','Exhale and curl the cable handle towards your shoulders, contracting your biceps.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale and slowly lower the cable handle back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'YwnI4ja'),
  ('db-0230', 'cable standing lift', 'Core', 'Cable', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Stand facing the cable machine with your feet shoulder-width apart.','Hold the cable handle with both hands and position it at waist height.','Engage your core and maintain a straight back throughout the exercise.','Keeping your arms straight, exhale and lift the cable handle up towards your opposite shoulder, rotating your torso.','Pause for a moment at the top, then inhale and slowly lower the cable handle back to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'qFpAkpP'),
  ('db-0231', 'cable standing one arm triceps extension', 'Arms', 'Cable', 'triceps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart, facing the cable machine.','Hold the cable handle with your right hand, palm facing down, and position your arm so that it is fully extended and parallel to the ground.','Keep your elbow stationary and close to your body.','Slowly bend your elbow, lowering the cable handle towards the back of your head.','Pause for a moment at the bottom of the movement, then extend your arm back to the starting position.','Repeat for the desired number of repetitions, then switch sides and perform the exercise with your left arm.']::text[], 'sYCcnon'),
  ('db-1376', 'cable standing one leg calf raise', 'Legs', 'Cable', 'calves', ARRAY['ankles','feet']::text[], ARRAY['Stand facing a cable machine with your feet shoulder-width apart.','Hold onto the cable machine for support.','Lift one leg off the ground and balance on the other leg.','Slowly raise your heel off the ground, lifting your body up onto your toes.','Pause for a moment at the top, then slowly lower your heel back down to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'fgc9Xdl'),
  ('db-0232', 'cable standing pulldown (with rope)', 'Arms', 'Cable', 'biceps', ARRAY['forearms','shoulders']::text[], ARRAY['Attach a rope to the cable machine at the highest setting.','Stand facing the machine with your feet shoulder-width apart.','Grasp the rope with an overhand grip, palms facing down.','Keep your back straight and core engaged throughout the exercise.','Pull the rope down towards your thighs, squeezing your biceps.','Pause for a moment at the bottom, then slowly release the rope back up.','Repeat for the desired number of repetitions.']::text[], 'CvPn9WV'),
  ('db-0233', 'cable standing rear delt row (with rope)', 'Shoulders', 'Cable', 'delts', ARRAY['trapezius','rhomboids','biceps']::text[], ARRAY['Stand facing a cable machine with your feet shoulder-width apart.','Hold the cable attachment with both hands, palms facing each other, and step back to create tension in the cable.','Keep your back straight and your core engaged.','Pull the cable towards your body, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement, then slowly release the cable back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZfyAGhK')
